package com.example.webhookhandler.controller;

import com.example.webhookhandler.model.PartnerWebhookRequest;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;

@RestController
@RequestMapping("/webhook")
public class WebhookController {
    @PostMapping("/receive")
    public ResponseEntity<String> handleWebhook(@RequestBody PartnerWebhookRequest request) {
        RestTemplate restTemplate = new RestTemplate();
        String content = restTemplate.getForObject(request.getUrl(), String.class);
        return ResponseEntity.ok(content);
    }
}